<?php require_once __DIR__.'/../includes/bootstrap.php';require_auth();$u=current_user($pdo);$uid=(int)$u['id'];$from=$_GET['from']??date('Y-m-01');$to=$_GET['to']??date('Y-m-t');$s=$pdo->prepare("SELECT title,status,priority,category,due_date,progress FROM tasks WHERE (user_id=? OR assigned_to=?) AND DATE(created_at) BETWEEN ? AND ? ORDER BY created_at DESC");$s->execute([$uid,$uid,$from,$to]);$rows=$s->fetchAll();?><!doctype html><html><head><meta charset="utf-8"><title>TaskFlow Report</title><style>body{font-family:Arial;margin:40px}table{width:100%;border-collapse:collapse}th,td{border:1px solid #bbb;padding:8px;text-align:left}@media print{button{display:none}}</style></head><body><button onclick="print()">Print / Save PDF</button><h1>TaskFlow Pro Report</h1><p><?=e($from)?> — <?=e($to)?></p><table><tr><th>Task</th><th>Status</th><th>Priority</th><th>Category</th><th>Due</th><th>Progress</th></tr><?php foreach($rows as $r):?><tr><td><?=e($r['title'])?></td><td><?=e(status_label($r['status']))?></td><td><?=e($r['priority'])?></td><td><?=e($r['category'])?></td><td><?=e($r['due_date'])?></td><td><?=$r['progress']?>%</td></tr><?php endforeach;?></table></body></html>